async def _ensure_workflow_context():
    context_manager = GriptapeNodes.ContextManager()
    if not context_manager.has_current_flow():
        top_level_flow_request = GetTopLevelFlowRequest()
        top_level_flow_result = await GriptapeNodes.ahandle_request(top_level_flow_request)
        if isinstance(top_level_flow_result, GetTopLevelFlowResultSuccess) and top_level_flow_result.flow_name is not None:
            flow_manager = GriptapeNodes.FlowManager()
            flow_obj = flow_manager.get_flow_by_name(top_level_flow_result.flow_name)
            context_manager.push_flow(flow_obj)

def execute_workflow(input: dict, *, workflow_executor: WorkflowExecutor | None=None, **kwargs: Any) -> dict | None:
    return asyncio.run(aexecute_workflow(input=input, workflow_executor=workflow_executor, **kwargs))

async def aexecute_workflow(input: dict, *, workflow_executor: WorkflowExecutor | None=None, **kwargs: Any) -> dict | None:
    await build_workflow()
    await _ensure_workflow_context()
    if workflow_executor is None:
        kwargs.setdefault('pickle_control_flow_result', False)
        workflow_executor = LocalWorkflowExecutor(skip_library_loading=True, workflows_to_register=[__file__], **kwargs)
    async with workflow_executor as executor:
        await executor.arun(flow_input=input, **kwargs)
    return executor.output

if __name__ == '__main__':
    logging.basicConfig(level=logging.INFO)
    parser = argparse.ArgumentParser()
    LocalWorkflowExecutor.add_cli_arguments(parser, pickle_control_flow_result_default=False)
    parser.add_argument('--json-input', default=None, help='JSON string containing parameter values. Takes precedence over individual parameter arguments if provided.')
    parser.add_argument('--exec_out', dest='exec_out', default=None, help='Connection to the next node in the execution chain')
    parser.add_argument('--prompt', dest='prompt', default=None, help='Text description of the specific target element or asset to be rotoscoped (e.g., "actor in foreground", "car", "helmet"). Used by Grounding DINO to establish the initial tracking area.')
    parser.add_argument('--box_threshold', dest='box_threshold', default=None, help="Detection sensitivity for the object's initial bounding box on the anchor frame. Lower values are more aggressive for tricky tracking areas; higher values prevent false positives on cluttered background plates.")
    parser.add_argument('--text_threshold', dest='text_threshold', default=None, help='Confidence threshold for matching the text prompt to visual characteristics on your plate. Tighten this value if the detector begins accidentally selecting neighboring objects with similar textures or colors.')
    parser.add_argument('--output_path', dest='output_path', default=None, help='The directory location and filename where the generated tracking mask video or image data will be written out. Feeds directly into a Nuke Write node')
    parser.add_argument('--input_video', dest='input_video', default=None, help='New parameter')
    parser.add_argument('--prompt_frame_idx', dest='prompt_frame_idx', default=None, help='The absolute frame number within your Nuke image sequence where the text prompt detection occurs. SAM2 uses this frame as the ground-truth anchor to calculate the mask forwards and backwards through the shot.')
    args = parser.parse_args()
    flow_input = {}
    if args.json_input is not None:
        flow_input = json.loads(args.json_input)
    if args.json_input is None:
        if 'Start Flow' not in flow_input:
            flow_input['Start Flow'] = {}
        if args.exec_out is not None:
            flow_input['Start Flow']['exec_out'] = args.exec_out
        if args.prompt is not None:
            flow_input['Start Flow']['prompt'] = args.prompt
        if args.box_threshold is not None:
            flow_input['Start Flow']['box_threshold'] = args.box_threshold
        if args.text_threshold is not None:
            flow_input['Start Flow']['text_threshold'] = args.text_threshold
        if args.output_path is not None:
            flow_input['Start Flow']['output_path'] = args.output_path
        if args.input_video is not None:
            flow_input['Start Flow']['input_video'] = args.input_video
        if args.prompt_frame_idx is not None:
            flow_input['Start Flow']['prompt_frame_idx'] = args.prompt_frame_idx
    executor = LocalWorkflowExecutor.from_cli_args(args, skip_library_loading=True, workflows_to_register=[__file__])
    workflow_output = execute_workflow(input=flow_input, workflow_executor=executor)
    print(workflow_output)
